import yaml
from tqdm import tqdm


def main() -> None:
    subset = ["coding", "math", "reasoning", "language", "instruction_following", "data_analysis"]
    setting = "default"
    for task in tqdm(subset):
        file_name = f"livebench_{task}_{setting}.yaml"
        try:
            with open(f"{file_name}", "w") as f:
                f.write("# Generated by _generate_configs.py\n")
                yaml.dump(
                    {
                        "include": f"_livebench_{setting}_yaml",
                        "task": f"livebench_{task}_{setting}",
                        "dataset_path": f"livebench/{task}",
                    },
                    f,
                )
        except FileExistsError:
            pass


if __name__ == "__main__":
    main()
